_____javascript
return await space.current.renderWidget({
  id: "starter-widget",
  name: "analog-clock",
  cols: 20,
  rows: 20,
  renderer: `async (parent) => {
  const size = 20;
  const cx = 10;
  const cy = 10;
  const r = 9;

  const pad = (n) => String(n).padStart(2, "0");

  function tick() {
    const now = new Date();
    const sec = now.getSeconds();
    const min = now.getMinutes() + sec / 60;
    const hr = (now.getHours() % 12) + min / 60;

    parent.innerHTML = "";

    const svgNS = "http://www.w3.org/2000/svg";
    const svg = document.createElementNS(svgNS, "svg");
    svg.setAttribute("viewBox", "0 0 20 20");
    svg.setAttribute("width", "100%");
    svg.setAttribute("height", "100%");
    svg.setAttribute("style", "display:block;background:#fff;");

    const circle = document.createElementNS(svgNS, "circle");
    circle.setAttribute("cx", cx);
    circle.setAttribute("cy", cy);
    circle.setAttribute("r", r);
    circle.setAttribute("fill", "white");
    circle.setAttribute("stroke", "black");
    circle.setAttribute("stroke-width", "0.4");
    svg.appendChild(circle);

    for (let i = 0; i < 12; i++) {
      const angle = ((i / 12) * Math.PI * 2) - Math.PI / 2;
      const x1 = cx + Math.cos(angle) * (r - 0.4);
      const y1 = cy + Math.sin(angle) * (r - 0.4);
      const x2 = cx + Math.cos(angle) * (r - (i % 3 === 0 ? 1.3 : 0.8));
      const y2 = cy + Math.sin(angle) * (r - (i % 3 === 0 ? 1.3 : 0.8));

      const mark = document.createElementNS(svgNS, "line");
      mark.setAttribute("x1", x1);
      mark.setAttribute("y1", y1);
      mark.setAttribute("x2", x2);
      mark.setAttribute("y2", y2);
      mark.setAttribute("stroke", "black");
      mark.setAttribute("stroke-width", i % 3 === 0 ? "0.35" : "0.18");
      svg.appendChild(mark);
    }

    function hand(angle, length, width, color) {
      const x2 = cx + Math.cos(angle) * length;
      const y2 = cy + Math.sin(angle) * length;
      const line = document.createElementNS(svgNS, "line");
      line.setAttribute("x1", cx);
      line.setAttribute("y1", cy);
      line.setAttribute("x2", x2);
      line.setAttribute("y2", y2);
      line.setAttribute("stroke", color);
      line.setAttribute("stroke-linecap", "round");
      line.setAttribute("stroke-width", width);
      svg.appendChild(line);
    }

    hand(((hr / 12) * Math.PI * 2) - Math.PI / 2, 4.8, 0.7, "black");
    hand(((min / 60) * Math.PI * 2) - Math.PI / 2, 6.8, 0.45, "black");
    hand(((sec / 60) * Math.PI * 2) - Math.PI / 2, 7.4, 0.2, "red");

    const center = document.createElementNS(svgNS, "circle");
    center.setAttribute("cx", cx);
    center.setAttribute("cy", cy);
    center.setAttribute("r", 0.35);
    center.setAttribute("fill", "black");
    svg.appendChild(center);

    const label = document.createElementNS(svgNS, "text");
    label.setAttribute("x", cx);
    label.setAttribute("y", 18.7);
    label.setAttribute("text-anchor", "middle");
    label.setAttribute("font-size", "1.1");
    label.setAttribute("font-family", "monospace");
    label.textContent = `${pad(now.getHours())}:${pad(now.getMinutes())}:${pad(now.getSeconds())}`;
    svg.appendChild(label);

    parent.appendChild(svg);
  }

  tick();
  setInterval(tick, 1000);
}`
})

