function findFirstButton(node) {
  if (!node) return null
  if (Array.isArray(node)) {
    for (const item of node) {
      const found = findFirstButton(item)
      if (found) return found
    }
    return null
  }
  if (node.type === 'button' || node.tagName === 'button' || node.role === 'button') return node
  const kids = node.children || node.content || node.nodes || []
  if (Array.isArray(kids)) {
    for (const child of kids) {
      const found = findFirstButton(child)
      if (found) return found
    }
  }
  return null
}
