Rewriting the clock widget fully now...
_____javascript
return await space.current.renderWidget({
  id: "analog-clock",
  name: "Analog Clock",
  cols: 10,
  rows: 10,
  renderer: async (parent) => {
    parent.innerHTML = `
      <div style="display:flex;align-items:center;justify-content:center;width:100%;height:100%;background:#111;">
        <svg id="clock" viewBox="0 0 200 200" width="100%" height="100%" style="max-width:180px;max-height:180px;">
          <circle cx="100" cy="100" r="96" fill="#f8f8f8" stroke="#222" stroke-width="4"></circle>
          <circle cx="100" cy="100" r="4" fill="#222"></circle>
          <g id="marks" stroke="#222" stroke-linecap="round"></g>
          <line id="hourHand" x1="100" y1="100" x2="100" y2="55" stroke="#222" stroke-width="6" stroke-linecap="round"></line>
          <line id="minuteHand" x1="100" y1="100" x2="100" y2="35" stroke="#222" stroke-width="4" stroke-linecap="round"></line>
          <line id="secondHand" x1="100" y1="110" x2="100" y2="25" stroke="#d11" stroke-width="2" stroke-linecap="round"></line>
        </svg>
      </div>
    `;

    const marks = parent.querySelector("#marks");
    for (let i = 0; i < 60; i++) {
      const isHour = i % 5 === 0;
      const angle = (i / 60) * Math.PI * 2 - Math.PI / 2;
      const r1 = isHour ? 82 : 88;
      const r2 = 94;
      const x1 = 100 + Math.cos(angle) * r1;
      const y1 = 100 + Math.sin(angle) * r1;
      const x2 = 100 + Math.cos(angle) * r2;
      const y2 = 100 + Math.sin(angle) * r2;
      const line = document.createElementNS("http://www.w3.org/2000/svg", "line");
      line.setAttribute("x1", x1);
      line.setAttribute("y1", y1);
      line.setAttribute("x2", x2);
      line.setAttribute("y2", y2);
      line.setAttribute("stroke-width", isHour ? "4" : "2");
      marks.appendChild(line);
    }

    const hourHand = parent.querySelector("#hourHand");
    const minuteHand = parent.querySelector("#minuteHand");
    const secondHand = parent.querySelector("#secondHand");

    const setHand = (el, angle, cx, cy) => {
      const len = parseFloat(el.getAttribute("y1")) - parseFloat(el.getAttribute("y2"));
      const rad = (Math.PI / 180) * angle - Math.PI / 2;
      const x2 = cx + Math.cos(rad) * len;
      const y2 = cy + Math.sin(rad) * len;
      el.setAttribute("x2", x2);
      el.setAttribute("y2", y2);
    };

    const tick = () => {
      const now = new Date();
      const s = now.getSeconds() + now.getMilliseconds() / 1000;
      const m = now.getMinutes() + s / 60;
      const h = (now.getHours() % 12) + m / 60;

      setHand(hourHand, h * 30, 100, 100);
      setHand(minuteHand, m * 6, 100, 100);
      setHand(secondHand, s * 6, 100, 100);
    };

    tick();
    setInterval(tick, 1000 / 30);
  }
})

